import numpy as np

def calculate_distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_distance = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        time_window_start, time_window_end = time_windows[i]

        distance_to_customer = calculate_distance(cur_truck_pos, customer_pos)

        if current_time + (distance_to_customer / truck_speed) <= time_window_end:
            if current_time + (distance_to_customer / truck_speed) >= time_window_start:
                wait_time = max(0, time_window_start - (current_time + (distance_to_customer / truck_speed)))
                total_time = current_time + (distance_to_customer / truck_speed) + wait_time
                if total_time < min_distance:
                    min_distance = total_time
                    best_node = i

    return best_node
